import React, { useState, useEffect } from 'react';
import { db } from '../../utils/firebase';
import { doc, getDoc, collection, getDocs, addDoc } from 'firebase/firestore';
import { Shield, MapPin, PlusCircle, AlertCircle } from 'lucide-react';

export default function MaterialDept() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [adminId, setAdminId] = useState('');
  const [password, setPassword] = useState('');
  
  // State management
  const [assignedArea, setAssignedArea] = useState(''); 
  const [logisticsSector, setLogisticsSector] = useState('');
  const [workersList, setWorkersList] = useState([]);

  // Auth Handler
  const handleAdminAuthGate = async (e) => {
    e.preventDefault();
    try {
      const vendorRef = doc(db, "vendors", adminId.trim());
      const vendorSnap = await getDoc(vendorRef);

      if (vendorSnap.exists()) {
        const data = vendorSnap.data();
        if (String(data.password) === String(password)) {
          // Firebase se data lekar local state mein set kar rahe hain
          const area = data.targetArea || 'No Area Assigned';
          const sector = data.logisticsSectorType || 'General';
          
          setAssignedArea(area);
          setLogisticsSector(sector);
          setIsAuthenticated(true);
        } else {
          alert("Invalid Password.");
        }
      } else {
        alert("Vendor ID not found.");
      }
    } catch (err) {
      console.error(err);
    }
  };

  // Fetch Workers (Dependency array mein assignedArea zaroori hai)
  useEffect(() => {
    if (isAuthenticated && assignedArea && assignedArea !== 'No Area Assigned') {
      const fetchWorkers = async () => {
        try {
          const q = collection(db, "vendors", assignedArea.trim(), "workers");
          const snap = await getDocs(q);
          setWorkersList(snap.docs.map(d => ({ id: d.id, ...d.data() })));
        } catch (err) {
          console.error("Path error: ", err);
        }
      };
      fetchWorkers();
    }
  }, [isAuthenticated, assignedArea]);

  // UI Render...
  return (
    <div style={{ padding: '24px', backgroundColor: '#F8FAFC', minHeight: '100vh' }}>
      {!isAuthenticated ? (
        <div style={{ maxWidth: '400px', margin: '100px auto', background: '#fff', padding: '30px', borderRadius: '10px' }}>
          <h2>Material Dept Login</h2>
          <input placeholder="Admin ID" onChange={(e) => setAdminId(e.target.value)} style={{ width: '100%', marginBottom: '10px' }} />
          <input type="password" placeholder="Password" onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', marginBottom: '10px' }} />
          <button onClick={handleAdminAuthGate} style={{ width: '100%', padding: '10px' }}>Login</button>
        </div>
      ) : (
        <div>
           {/* Header display */}
           <div style={{ display: 'flex', gap: '20px', background: '#0F172A', color: '#fff', padding: '20px', borderRadius: '10px' }}>
             <p>Area: <b>{assignedArea}</b></p>
             <p>Sector: <b>{logisticsSector}</b></p>
           </div>
           
           {/* Agar area assign nahi hai to alert */}
           {assignedArea === 'No Area Assigned' && (
             <div style={{ marginTop: '20px', padding: '20px', background: '#FEE2E2', color: '#B91C1C' }}>
               <AlertCircle /> Admin se area assign karwayein!
             </div>
           )}
        </div>
      )}
    </div>
  );
}
